import axios from 'axios';

const API_URL = '/api/forum';

// Get all forum posts with optional filters
const getPosts = async (category = '', sortBy = 'latest') => {
  const response = await axios.get(`${API_URL}/posts`, {
    params: { category, sortBy }
  });
  return response.data;
};

// Get a single post by ID
const getPostById = async (postId) => {
  const response = await axios.get(`${API_URL}/posts/${postId}`);
  return response.data;
};

// Create a new forum post
const createPost = async (postData) => {
  const response = await axios.post(`${API_URL}/posts`, postData);
  return response.data;
};

// Update a forum post
const updatePost = async (postId, postData) => {
  const response = await axios.put(`${API_URL}/posts/${postId}`, postData);
  return response.data;
};

// Delete a forum post
const deletePost = async (postId) => {
  const response = await axios.delete(`${API_URL}/posts/${postId}`);
  return response.data;
};

// Like/unlike a post
const likePost = async (postId) => {
  const response = await axios.post(`${API_URL}/posts/${postId}/like`);
  return response.data;
};

// Bookmark/unbookmark a post
const bookmarkPost = async (postId) => {
  const response = await axios.post(`${API_URL}/posts/${postId}/bookmark`);
  return response.data;
};

// Get user bookmarked posts
const getUserBookmarks = async () => {
  const response = await axios.get(`${API_URL}/bookmarks`);
  return response.data;
};

// Add a comment to a post
const addComment = async (postId, commentData) => {
  const response = await axios.post(`${API_URL}/posts/${postId}/comments`, commentData);
  return response.data;
};

// Delete a comment
const deleteComment = async (postId, commentId) => {
  const response = await axios.delete(`${API_URL}/posts/${postId}/comments/${commentId}`);
  return response.data;
};

// Like/unlike a comment
const likeComment = async (postId, commentId) => {
  const response = await axios.post(`${API_URL}/posts/${postId}/comments/${commentId}/like`);
  return response.data;
};

// Get posts by search term
const searchPosts = async (searchTerm) => {
  const response = await axios.get(`${API_URL}/search`, {
    params: { query: searchTerm }
  });
  return response.data;
};

// Get user posts
const getUserPosts = async () => {
  const response = await axios.get(`${API_URL}/user/posts`);
  return response.data;
};

// Get trending posts
const getTrendingPosts = async (limit = 5) => {
  const response = await axios.get(`${API_URL}/trending`, {
    params: { limit }
  });
  return response.data;
};

// Get forum categories
const getCategories = async () => {
  const response = await axios.get(`${API_URL}/categories`);
  return response.data;
};

// Upload image for a post
const uploadImage = async (formData) => {
  const response = await axios.post(`${API_URL}/upload`, formData, {
    headers: {
      'Content-Type': 'multipart/form-data'
    }
  });
  return response.data;
};

const forumService = {
  getPosts,
  getPostById,
  createPost,
  updatePost,
  deletePost,
  likePost,
  bookmarkPost,
  getUserBookmarks,
  addComment,
  deleteComment,
  likeComment,
  searchPosts,
  getUserPosts,
  getTrendingPosts,
  getCategories,
  uploadImage
};

export default forumService;
